(function(){"use strict";function q(a,o=20,e=500){if(!Array.isArray(a)||a.length<10)return null;const l=a[a.length-1],M=a.slice(Math.max(0,a.length-90)),n=[];for(let t=1;t<M.length;t++){const r=Math.log(M[t]/M[t-1]);Number.isFinite(r)&&n.push(r)}if(n.length<5)return null;const A=n.reduce((t,r)=>t+r,0)/n.length,S=n.reduce((t,r)=>t+(r-A)**2,0)/n.length,v=Math.sqrt(S),p=Math.max(-.02,Math.min(.02,A)),g=Math.max(.005,Math.min(.08,v)),z=p-.5*g*g,B=(o+1)*e,m=new Float64Array(B),f=new Float64Array(e);for(let t=0;t<e;t++){let r=l;m[0*e+t]=r;for(let s=1;s<=o;s++){const u=Math.max(1e-9,Math.random()),i=Math.random(),w=Math.sqrt(-2*Math.log(u))*Math.cos(2*Math.PI*i);r=r*Math.exp(z+g*w),m[s*e+t]=r}f[t]=r}const c=(t,r)=>{const s=Array.from(t).sort((i,w)=>i-w),u=Math.min(s.length-1,Math.max(0,Math.floor(r/100*s.length)));return s[u]},d=new Array(o+1),x=new Array(o+1),y=new Array(o+1),F=new Array(o+1),P=new Array(o+1),h=new Float64Array(e);for(let t=0;t<=o;t++){for(let r=0;r<e;r++)h[r]=m[t*e+r];d[t]=c(h,5),x[t]=c(h,25),y[t]=c(h,50),F[t]=c(h,75),P[t]=c(h,95)}let b=0;for(let t=0;t<e;t++)f[t]>l&&b++;return{p5:d,p25:x,p50:y,p75:F,p95:P,days:o,simulations:e,profitProb:b/e*100,median:c(f,50),worst5:c(f,5),best5:c(f,95),lastPrice:l,mu:p,sigma:g}}self.onmessage=a=>{const{id:o,prices:e,days:l,simulations:M}=a.data||{};try{const n=q(e,l,M);self.postMessage({id:o,result:n})}catch(n){self.postMessage({id:o,error:(n==null?void 0:n.message)||String(n)})}}})();
